  ('social-worker-moex-06315', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某福利服務機構清查社區現有資源標示配比（mapping），試圖匯集大量與服務供給面相關之資訊，藉此 確認整個服務體系的現況與範疇；此為何種需求評量方法？', '["表達性需求（expressed need）", "感受性需求（perceived need）", "規範性需求（normative need）", "相對性需求（relative need）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
